import inspect
import logging
from actions.search_element import search_element
from utils.error import messageError
from selenium.webdriver.common.by import By


def get_calendar(driver):
    logging.info(f"START || {inspect.currentframe().f_code.co_name}")
    try:
        calendar_table = search_element(driver, (
            By.XPATH,
            '//table[contains(@class, "table") and contains(@class, "table-bordered") and contains(@class, "table-condesed")]'
        ))

        # Parse the multi-week table in the browser to preserve DOM context (rowspan/sibling nodes).
        calendar = driver.execute_script("""
            const table = arguments[0];

            const textOrNull = (value) => {
                const cleaned = (value || '').replace(/\s+/g, ' ').trim();
                return cleaned || null;
            };

            const parseToggleId = (href) => {
                const match = (href || '').match(/toggle\\('?(\\d+)'?\\)/);
                return match ? match[1] : null;
            };

            const parseRequestArgs = (onclickValue) => {
                const match = (onclickValue || '').match(/cambio\\((.*)\\)/);
                if (!match) {
                    return null;
                }

                const values = [];
                const regex = /'([^']*)'/g;
                let current;
                while ((current = regex.exec(match[1])) !== null) {
                    values.push(current[1]);
                }

                if (!values.length) {
                    return null;
                }

                return {
                    raw: onclickValue,
                    action_code: values[0] || null,
                    unix_time: values[1] || null,
                    day_number: values[2] || null,
                    month: values[3] || null,
                    slot_code: values[4] || null,
                };
            };

            const getCellData = (cell) => {
                if (!cell) {
                    return {
                        status: null,
                        request_button: null,
                        assignees: []
                    };
                }

                const statusClass = Array.from(cell.classList).find((className) => (
                    className === 'warning' || className === 'danger' || className === 'info' || className === 'active'
                )) || null;

                const requestButton = cell.querySelector('input[name="accion"][value="Solicitar Turno"]');
                const requestData = requestButton
                    ? {
                        label: requestButton.value || 'Solicitar Turno',
                        onclick: requestButton.getAttribute('onclick') || null,
                        parsed_onclick: parseRequestArgs(requestButton.getAttribute('onclick') || '')
                    }
                    : null;

                const links = Array.from(cell.querySelectorAll('a[href*="javascript:toggle"]'));
                const assignees = links.map((link) => {
                    const toggleId = parseToggleId(link.getAttribute('href') || '');
                    let phone = null;
                    if (toggleId) {
                        const phoneNode = cell.querySelector(`#capa${toggleId} font`) || table.querySelector(`#capa${toggleId} font`);
                        phone = textOrNull(phoneNode ? phoneNode.textContent : null);
                    }

                    return {
                        id: toggleId,
                        name: textOrNull(link.textContent),
                        phone: phone,
                    };
                }).filter((item) => item.name);

                return {
                    status: statusClass,
                    request_button: requestData,
                    assignees: assignees,
                };
            };

            const sections = [];
            const theads = Array.from(table.querySelectorAll(':scope > thead'));

            theads.forEach((thead) => {
                const tbody = thead.nextElementSibling;
                if (!tbody || tbody.tagName !== 'TBODY') {
                    return;
                }

                const headerRows = thead.querySelectorAll('tr');
                if (headerRows.length < 2) {
                    return;
                }

                const dateHeaders = Array.from(headerRows[0].querySelectorAll('th')).slice(1).map((th) => textOrNull(th.textContent));
                const weekdayHeaders = Array.from(headerRows[1].querySelectorAll('th')).map((th) => textOrNull(th.textContent));

                const days = weekdayHeaders.map((weekday, index) => ({
                    weekday: weekday,
                    date: dateHeaders[index] || null,
                }));

                const slotRows = Array.from(tbody.querySelectorAll('tr')).filter((row) => row.querySelector('td.info'));
                const slots = slotRows.map((firstRow) => {
                    const secondRow = firstRow.nextElementSibling && !firstRow.nextElementSibling.querySelector('td.info')
                        ? firstRow.nextElementSibling
                        : null;

                    const timeCell = firstRow.querySelector('td.info');
                    const timeRange = textOrNull(timeCell ? timeCell.innerText.replace(/\\n/g, ' ') : null);

                    const firstRowCells = Array.from(firstRow.querySelectorAll('td')).slice(1);
                    const secondRowCells = secondRow ? Array.from(secondRow.querySelectorAll('td')) : [];

                    const entries = days.map((day, dayIndex) => {
                        const topData = getCellData(firstRowCells[dayIndex]);
                        const bottomData = getCellData(secondRowCells[dayIndex]);

                        const combinedAssignees = [...topData.assignees, ...bottomData.assignees];
                        const combinedStatus = topData.status || bottomData.status;
                        const requestButton = topData.request_button || bottomData.request_button;

                        return {
                            weekday: day.weekday,
                            date: day.date,
                            status: combinedStatus,
                            request_button: requestButton,
                            assignees: combinedAssignees,
                        };
                    });

                    return {
                        time_range: timeRange,
                        entries: entries,
                    };
                });

                sections.push({
                    days: days,
                    slots: slots,
                });
            });

            return {
                sections: sections,
            };
        """, calendar_table)

        return driver, calendar
    except Exception as e:
        raise messageError(
            f"Error {inspect.currentframe().f_code.co_name}: {e}")

